INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c63fc55e-ec11-4a97-8b58-c65600a92bdb',
  '00000000-0000-0000-0000-000000000001',
  $escape$Foundry Smart Contract Storage Optimization$escape$,
  $escape$When storing data in a foundry smart contract, consider the storage layout to minimize SLOAD and SSTORE costs. Foundry uses a dictionary-based storage system, where each key is stored in a slot. Slots are packed into a 256-bit word, with the last slot padded to 8 bytes. SLOAD and SSTORE operations are expensive, so avoid unnecessary storage access. To minimize collisions, use unique and prefix-free keys. Consider using nested structs to group related data. For example, a user contract might use a nested struct `user` containing `address`, `name`, and `balance` fields.$escape$,
  $escape$contract User {    struct user {        address addr;        string name;        uint balance;    }    mapping (address => user) users;$escape$,
  $escape$solidity$escape$,
